from instructor import from_openai
from pydantic import BaseModel, Field
from vex import verify

class PaymentIntent(BaseModel):
    amount: int
    currency: str = Field(..., pattern='^[A-Z]{3}$')
    last4: str = Field(..., pattern='^\d{4}$')
    status: Literal['pending', 'succeeded', 'failed']

client = from_openai(openai_client)
@verify()
def extract_payment(text: str) -> PaymentIntent:
    return client.chat.completions.create(
        model='gpt-4o',
        response_model=PaymentIntent,
        messages=[{'role': 'user', 'content': text}]
    )

import { fromOpenai } from '@instructor-ai/instructor';
import { z } from 'zod';
import { verify } from '@vex/sdk';

const KYCConsentSchema = z.object({
  customerId: z.string().uuid(),
  consentGiven: z.literal(true),
  dataCategories: z.array(z.enum(['contact', 'financial', 'identity'])),
  withdrawalDate: z.string().optional(),
  signature: z.string().min(32)
});

const client = fromOpenai(openai);
const extractConsent = verify(async (text: string) => {
  return client.chat.completions.create({
    model: 'gpt-4o',
    responseModel: KYCConsentSchema,
    messages: [{ role: 'user', content: text }]
  });
});
